parameters.jsCode:
// Transform Apollo results to leads format
const items = $input.all();
const leads = [];

for (const item of items) {
  const people = item.json.people || [];
  for (const p of people) {
    if (!p.email) continue;

    const org = p.organization || {};
    const country = (p.country || org.country || '').toUpperCase();
    const countryMap = {
      'SOUTH KOREA': 'KR', 'KOREA': 'KR', 'JAPAN': 'JP',
      'GERMANY': 'DE', 'UNITED STATES': 'US', 'USA': 'US',
      'VIETNAM': 'VN', 'THAILAND': 'TH', 'INDIA': 'IN',
      'CHINA': 'CN', 'UNITED KINGDOM': 'GB', 'UK': 'GB',
      'FRANCE': 'FR', 'CANADA': 'CA', 'AUSTRALIA': 'AU',
      'UAE': 'AE', 'SINGAPORE': 'SG'
    };
    const countryCode = countryMap[country] || country.substring(0, 2);

    // Determine lead type from search context
    const titles = (p.title || '').toLowerCase();
    const isManufacturer = titles.includes('export') || 
      titles.includes('ceo') || titles.includes('manufacturing');
    const leadType = isManufacturer ? 'manufacturer' : 'buyer';

    // Score based on data completeness
    let score = 10;
    if (p.email_status === 'verified') score += 10;
    if (p.phone_numbers?.length) score += 5;
    if (org.website_url) score += 5;
    if (org.estimated_num_employees > 50) score += 5;

    leads.push({
      json: {
        source: 'apollo',
        company_name: org.name || '',
        contact_name: p.name || (p.first_name + ' ' + p.last_name),
        email: p.email,
        phone: p.phone_numbers?.[0]?.sanitized_number || null,
        website: org.website_url || null,
        category: org.industry || null,
        region: countryCode,
        country: countryCode,
        lead_type: leadType,
        segment: leadType === 'manufacturer' ? 'global_mfg' : 'global_buyer',
        score: score,
        raw_data: {
          apollo_id: p.id,
          title: p.title,
          linkedin_url: p.linkedin_url,
          org_id: org.id,
          employees: org.estimated_num_employees,
          industry: org.industry,
          keywords: org.keywords
        }
      }
    });
  }
}

return leads;

